import{_ as i,o as l,c as e,e as a}from"./app.a158ac49.js";const o={},r=a('<h1 id="seo搜索引擎优化面试总结" tabindex="-1"><a class="header-anchor" href="#seo搜索引擎优化面试总结" aria-hidden="true">#</a> Seo搜索引擎优化面试总结</h1><h2 id="对于一个新项目你第一步应该做什么" tabindex="-1"><a class="header-anchor" href="#对于一个新项目你第一步应该做什么" aria-hidden="true">#</a> 对于一个新项目你第一步应该做什么</h2><ol><li>第一步站内初步优化 <ul><li>根据产品选择网站关键词，设置TDK标签（Title,description,KeyWord）</li><li>主页导航栏设置是否合理</li><li>图片是否添加ALT属性</li><li>网站框架和内容是否符合SEO规范</li><li>服务器优化（访问速度，sitemap，自动向百度提交新的文章链接，设置robots协议）</li></ul></li><li>第二步：内容更新 <ul><li>定期更新文章</li><li>分析网站的长尾关键词，收集整理以后根据不同的组合，为网站更新文章</li></ul></li><li>第三步：站外推广 <ul><li>交换友情链接</li><li>发布外链</li></ul></li></ol><h2 id="日常工作" tabindex="-1"><a class="header-anchor" href="#日常工作" aria-hidden="true">#</a> 日常工作</h2><ol><li>更新发布文章</li><li>交换友情链接</li><li>发布外链</li><li>监控并记录网站数据</li><li>发现死练及时向百度提交</li><li>定期更新sitemap网页地图</li><li>有不想被爬虫抓取的页面及时设置robots协议，防止对网站权重造成影响</li><li>在有条件条件的情况下应该设置自动提交API，一旦有新的文章或页面自动向百度提交</li></ol><h2 id="建站系统" tabindex="-1"><a class="header-anchor" href="#建站系统" aria-hidden="true">#</a> 建站系统</h2><ol><li>WordPress</li><li>VuePress（本站使用此系统）</li><li>dedecms（织梦cms）</li><li>自己开发框架</li><li>其他不一一列举</li></ol><h2 id="你认为一个网站一天发布几篇文章合适" tabindex="-1"><a class="header-anchor" href="#你认为一个网站一天发布几篇文章合适" aria-hidden="true">#</a> 你认为一个网站一天发布几篇文章合适？</h2><blockquote><p>我认为网站前期发布的文章过多，这可能会导致质量下降，并且用户也不会阅读所有的文章</p><p>发布的文章尽可能高质量、原创度高，然后就是定期更新 让搜索引擎有规律的抓取数据</p><p>我建议是每天1-2篇文章能得到SEO优化最好的效果</p></blockquote><h2 id="robots协议是什么" tabindex="-1"><a class="header-anchor" href="#robots协议是什么" aria-hidden="true">#</a> robots协议是什么</h2><ol><li>robots协议可以设置搜索引擎可抓取的页面，告诉搜索引擎的爬虫哪些页面可以抓取哪些页面不能抓取</li><li>防止搜索引擎抓取对网站推广无用的内容，影响网站的权重</li><li>robots协议仅对搜索引擎的爬虫有效，对于野生爬虫是没有任何效果的</li></ol>',11),t=[r];function s(d,h){return l(),e("div",null,t)}const n=i(o,[["render",s],["__file","SeoOffer.html.vue"]]);export{n as default};
